487	///
488	/// ```c
489	/// static void set2 (lua_State *L, IdxT i, IdxT j) {
490	///   lua_seti(L, 1, i);
491	///   lua_seti(L, 1, j);
492	/// }
493	/// ```
494	fn set2(state: &mut LuaState, i: IdxT, j: IdxT) -> Result<(), LuaError> {
495	    // First seti pops the stack top; second seti pops the new top.
496	    state.table_set_i(1, i as i64)?;
497	    state.table_set_i(1, j as i64)?;
