fn math_random(state: &mut LuaState) -> Result<usize, LuaError> {
    // C: RanState *state = (RanState *)lua_touserdata(L, lua_upvalueindex(1));
    // TODO(port): RanState is stored as typed userdata in closure upvalue 1.
